80	pub fn jaccard(a: &[u64], b: &[u64]) -> f64 {
81	    if a.is_empty() && b.is_empty() {
82	        return 1.0;
83	    }
84	    let set_a: HashSet<u64> = a.iter().copied().collect();
85	    let set_b: HashSet<u64> = b.iter().copied().collect();
86	    let intersection = set_a.intersection(&set_b).count();
87	    let union = set_a.union(&set_b).count();
88	    if union == 0 {
89	        return 0.0;
90	    }
91	    intersection as f64 / union as f64
92	}
