98	pub fn make_pair(a: &FunctionInfo, b: &FunctionInfo, score: f64) -> DuplicatePair {
99	    let (left, right) = order_endpoints(a, b);
100	    DuplicatePair {
101	        score,
102	        left: PairEndpoint {
103	            file: left.file.clone(),
104	            start_line: left.start_line,
105	            end_line: left.end_line,
106	            nodes: left.node_hashes.len(),
107	        },
108	        right: PairEndpoint {
109	            file: right.file.clone(),
110	            start_line: right.start_line,
111	            end_line: right.end_line,
112	            nodes: right.node_hashes.len(),
113	        },
114	    }
115	}
