121	pub fn find_duplicate_pairs(
122	    functions: &[FunctionInfo],
123	    threshold: f64,
124	    min_lines: usize,
125	    min_nodes: usize,
126	) -> Vec<DuplicatePair> {
127	    let candidates: Vec<&FunctionInfo> = functions
128	        .iter()
129	        .filter(|f| source_lines(f) >= min_lines && f.node_hashes.len() >= min_nodes)
130	        .collect();
131	
132	    let mut pairs: Vec<DuplicatePair> = Vec::new();
133	
134	    for i in 0..candidates.len() {
135	        for j in (i + 1)..candidates.len() {
136	            let a = candidates[i];
137	            let b = candidates[j];
138	            if is_same_location(a, b) {
139	                continue;
140	            }
141	            let score = jaccard(&a.node_hashes, &b.node_hashes);
142	            if score >= threshold {
143	                pairs.push(make_pair(a, b, score));
144	            }
145	        }
146	    }
147	
148	    pairs.sort_by(|a, b| {
149	        b.score
150	            .partial_cmp(&a.score)
151	            .unwrap_or(std::cmp::Ordering::Equal)
152	            .then_with(|| a.left.file.cmp(&b.left.file))
153	            .then_with(|| a.left.start_line.cmp(&b.left.start_line))
154	            .then_with(|| a.right.file.cmp(&b.right.file))
155	            .then_with(|| a.right.start_line.cmp(&b.right.start_line))
156	    });
157	
158	    pairs
159	}
