161	fn order_endpoints<'a>(
162	    a: &'a FunctionInfo,
163	    b: &'a FunctionInfo,
164	) -> (&'a FunctionInfo, &'a FunctionInfo) {
165	    let cmp = a
166	        .file
167	        .cmp(&b.file)
168	        .then_with(|| a.start_line.cmp(&b.start_line));
169	    if cmp == std::cmp::Ordering::Greater {
170	        (b, a)
171	    } else {
172	        (a, b)
173	    }
174	}
