144	fn extract_rust_functions(
145	    node: tree_sitter::Node,
146	    source: &str,
147	    file: &str,
148	    functions: &mut Vec<FunctionInfo>,
149	) {
150	    match node.kind() {
151	        "function_item" => {
152	            functions.push(make_function_info(node, source, file, &RUST_CONFIG));
153	        }
154	        "let_declaration" => {
155	            extract_rust_let_declaration(node, source, file, functions);
156	        }
157	        _ => {
158	            for child in children_of(node) {
159	                extract_rust_functions(child, source, file, functions);
