174	fn extract_rust_let_declaration(
175	    node: tree_sitter::Node,
176	    source: &str,
177	    file: &str,
178	    functions: &mut Vec<FunctionInfo>,
179	) {
180	    if let Some(val) = find_child_by_field(node, "value")
181	        && val.kind() == "closure_expression"
182	    {
183	        functions.push(make_function_info(node, source, file, &RUST_CONFIG));
184	    }
185	    for child in children_of(node) {
186	        if child.kind() != "closure_expression" {
187	            extract_rust_functions(child, source, file, functions);
