192	fn extract_jsts_export_statement(
193	    node: tree_sitter::Node,
194	    source: &str,
195	    file: &str,
196	    config: &LangConfig,
197	    functions: &mut Vec<FunctionInfo>,
198	) {
199	    let fn_decls: Vec<_> = children_of(node)
200	        .into_iter()
201	        .filter(|c| c.kind() == "function_declaration")
202	        .collect();
203	    if fn_decls.is_empty() {
204	        for child in children_of(node) {
205	            extract_jsts_functions(child, source, file, config, functions);
206	        }
207	    } else {
208	        for child in fn_decls {
