242	fn try_extract_jsts_node(
243	    node: tree_sitter::Node,
244	    source: &str,
245	    file: &str,
246	    config: &LangConfig,
247	    functions: &mut Vec<FunctionInfo>,
248	) -> bool {
249	    match node.kind() {
250	        "function_declaration" => functions.push(make_function_info(node, source, file, config)),
251	        "export_statement" => extract_jsts_export_statement(node, source, file, config, functions),
252	        "lexical_declaration" => {
253	            extract_jsts_lexical_declaration(node, source, file, config, functions)
254	        }
255	        "class_body" => extract_jsts_class_body(node, source, file, config, functions),
