261	fn extract_jsts_functions(
262	    node: tree_sitter::Node,
263	    source: &str,
264	    file: &str,
265	    config: &LangConfig,
266	    functions: &mut Vec<FunctionInfo>,
267	) {
268	    if !try_extract_jsts_node(node, source, file, config, functions) {
269	        for child in children_of(node) {
