289	pub fn find_child_by_field<'a>(
290	    node: tree_sitter::Node<'a>,
291	    field: &str,
292	) -> Option<tree_sitter::Node<'a>> {
293	    let mut cursor = node.walk();
294	    for child in node.children(&mut cursor) {
295	        if child.kind() == field {
296	            return Some(child);
297	        }
298	    }
299	    node.child_by_field_name(field)
300	}
301	
302	pub fn make_function_info(
303	    node: tree_sitter::Node,
304	    source: &str,
305	    file: &str,
306	    config: &LangConfig,
307	) -> FunctionInfo {
308	    let start_line = node.start_position().row + 1;
309	    let end_line = node.end_position().row + 1;
310	    let hashes = collect_subtree_hashes(node, source, config);
311	    FunctionInfo {
312	        file: file.to_string(),
313	        start_line,
314	        end_line,
315	        node_hashes: hashes,
316	    }
317	}
