319	fn normalize_node_text(node: tree_sitter::Node, source: &str, config: &LangConfig) -> String {
320	    let kind = node.kind();
321	    if config.identifier_kinds.contains(&kind) {
322	        return "_ID".to_string();
323	    }
324	    if config.literal_kinds.contains(&kind) {
325	        return "_LIT".to_string();
326	    }
327	    let start = node.start_byte();
328	    let end = node.end_byte();
329	    source[start..end].to_string()
330	}
331	
332	pub fn build_normalized_subtree(
333	    node: tree_sitter::Node,
334	    source: &str,
335	    config: &LangConfig,
336	) -> String {
337	    if node.child_count() == 0 {
338	        return normalize_node_text(node, source, config);
339	    }
340	    let mut parts = vec![format!("({}:", node.kind())];
341	    let mut cursor = node.walk();
342	    for child in node.children(&mut cursor) {
343	        parts.push(build_normalized_subtree(child, source, config));
344	    }
345	    parts.push(")".to_string());
346	    parts.join("")
347	}
