349	fn hash_str(s: &str) -> u64 {
350	    use std::hash::{Hash, Hasher};
351	    let mut h = std::collections::hash_map::DefaultHasher::new();
352	    s.hash(&mut h);
353	    h.finish()
354	}
355	
356	fn collect_subtree_hashes(node: tree_sitter::Node, source: &str, config: &LangConfig) -> Vec<u64> {
357	    let mut hashes = Vec::new();
358	    collect_hashes_recursive(node, source, config, &mut hashes);
359	    hashes.sort_unstable();
360	    hashes
361	}
362	
363	fn collect_hashes_recursive(
364	    node: tree_sitter::Node,
365	    source: &str,
366	    config: &LangConfig,
367	    hashes: &mut Vec<u64>,
368	) {
369	    let subtree = build_normalized_subtree(node, source, config);
370	    hashes.push(hash_str(&subtree));
371	    let mut cursor = node.walk();
372	    for child in node.children(&mut cursor) {
373	        collect_hashes_recursive(child, source, config, hashes);
374	    }
375	}
