4	proptest! {
5	    #[test]
6	    fn hashing_deterministic_for_valid_fn(name in "[a-z][a-z0-9_]{0,10}") {
7	        let src = format!("fn {}(x: i32) -> i32 {{ let a = x + 1; a * 2 }}", name);
8	        let mut p1 = make_parser();
9	        let mut p2 = make_parser();
10	        let tree1 = p1.parse(&src, None).unwrap();
11	        let tree2 = p2.parse(&src, None).unwrap();
12	        let mut fns1 = Vec::new();
13	        let mut fns2 = Vec::new();
14	        extract_functions(tree1.root_node(), &src, "test.rs", &mut fns1);
15	        extract_functions(tree2.root_node(), &src, "test.rs", &mut fns2);
16	        prop_assert_eq!(fns1.len(), fns2.len());
17	        for (f1, f2) in fns1.iter().zip(fns2.iter()) {
18	            prop_assert_eq!(&f1.node_hashes, &f2.node_hashes, "same source must produce same hashes");
19	        }
